const texto = ($json.output || '').replace(/\*\*/g, '*');
// Pega a resposta da IA

if (!texto || typeof texto !== 'string') {
  return [{ json: { message: texto || '', part: 1, total: 1 } }];
}
// Se nao veio texto ou nao e string, retorna vazio sem quebrar

const partes = texto
  .split(/\n\n+/)           // Divide o texto onde tiver 2+ quebras de linha (paragrafos)
  .map(p => p.trim())       // Remove espacos extras de cada parte
  .filter(p => p.length > 0); // Remove partes vazias

if (partes.length === 0) {
  return [{ json: { message: texto, part: 1, total: 1 } }];
}
// Se nao encontrou paragrafos, manda o texto inteiro como uma mensagem so

const total = partes.length;
return partes.map((msg, idx) => ({
  json: {
    message: msg,          // O texto desse pedaco
    part: idx + 1,         // Numero da parte (1, 2, 3...)
    total: total           // Total de partes
  }
}));
// Transforma cada paragrafo em um item separado do n8n
// Assim o node seguinte (enviar mensagem) roda uma vez por parte
// Resultado: a IA manda varias mensagens curtas em vez de um textao
